using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Text;

public class ReportController : Controller
{
    private readonly ILogger<ReportController> _logger;

    public ReportController(ILogger<ReportController> logger)
    {
        _logger = logger;
    }

    // Was: btnExport_Click with Response.Write + Response.End()
    // Now: Return a FileResult — the framework handles content headers and
    //      stream lifecycle. No need to clear/end the response manually.
    [HttpPost]
    public IActionResult Export(CancellationToken cancellationToken)
    {
        var data = GenerateReport(cancellationToken);
        var bytes = Encoding.UTF8.GetBytes(data);
        return File(bytes, "text/csv", "report.csv");
    }

    // Was: btnRedirect_Click with Response.Redirect(url, true) + ThreadAbortException catch
    // Now: Return RedirectResult — no thread abort, no exception-based control flow.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // No ThreadAbortException catch needed — Redirect() just returns a result,
        // it never throws.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport(CancellationToken cancellationToken = default)
    {
        // Pass cancellationToken to any long-running work (DB queries, etc.)
        // so the request can be cancelled if the client disconnects.
        cancellationToken.ThrowIfCancellationRequested();
        return "col1,col2\nval1,val2";
    }

    private void ProcessRequest() { /* ... */ }
    private void LogError(Exception ex) => _logger.LogError(ex, "Request processing failed");
}

